import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);

  const [tab, setTab] = useState('users');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    const [u, p, c] = await Promise.all([
      API.get('/admin/users'),
      API.get('/admin/posts'),
      API.get('/admin/comments'),
    ]);

    setUsers(u.data);
    setPosts(p.data);
    setComments(c.data);
  };

  // USERS
  const toggleStatus = async (id) => {
    const { data } = await API.put(`/admin/users/${id}/status`);
    setUsers(users.map(u => (u._id === id ? data.user : u)));
  };

  // POSTS
  const removePost = async (id) => {
    const { data } = await API.put(`/admin/posts/${id}/remove`);
    setPosts(posts.map(p => (p._id === id ? data.post : p)));
  };

  const restorePost = async (id) => {
    const { data } = await API.put(`/admin/posts/${id}/restore`);
    setPosts(posts.map(p => (p._id === id ? data.post : p)));
  };

  // COMMENTS
  const removeComment = async (id) => {
    const { data } = await API.put(`/admin/comments/${id}/remove`);
    setComments(comments.map(c => (c._id === id ? data.comment : c)));
  };

  const restoreComment = async (id) => {
    const { data } = await API.put(`/admin/comments/${id}/restore`);
    setComments(comments.map(c => (c._id === id ? data.comment : c)));
  };

  // VIEW POST
  const viewPost = (postId) => {
    navigate(`/post/${postId}`);
  };

  const isDark = document.body.classList.contains("dark-mode");

  const styles = {
    page: {
      background: isDark
        ? 'linear-gradient(135deg, #1a0010, #3b0a24)'
        : 'linear-gradient(135deg, #ffe6ef, #f7c6d9)',
      minHeight: '100vh',
      padding: '40px',
      fontFamily: 'Georgia, serif',
    },

    container: {
      maxWidth: '1150px',
      margin: 'auto',
      background: isDark ? '#2e091e' : '#ffffffcc',
      backdropFilter: 'blur(10px)',
      padding: '30px',
      borderRadius: '25px',
      boxShadow: isDark
        ? '0 10px 30px rgba(0,0,0,0.5)'
        : '0 10px 30px rgba(0,0,0,0.15)',
      border: isDark ? '1px solid #4a2a3a' : '1px solid #fff',
    },

    tabs: {
      display: 'flex',
      justifyContent: 'center',
      gap: '12px',
      marginBottom: '25px',
    },

    tabBtn: {
      padding: '10px 22px',
      border: 'none',
      borderRadius: '50px',
      cursor: 'pointer',
      fontWeight: 'bold',
      background: isDark ? '#3a1b2b' : '#fff',
      color: isDark ? '#f5d6e6' : '#333',
      boxShadow: '0 3px 10px rgba(0,0,0,0.1)',
    },

    table: {
      width: '100%',
      borderCollapse: 'collapse',
      marginTop: '15px',
      borderRadius: '15px',
      overflow: 'hidden',
    },

    th: {
      background: isDark
        ? 'linear-gradient(90deg, #4a1f33, #3a1b2b)'
        : 'linear-gradient(90deg, rgb(12,75,52), rgb(20,110,75))',
      color: '#fff',
      padding: '14px',
      textAlign: 'left',
    },

    td: {
      padding: '14px',
      borderBottom: isDark ? '1px solid #3a1b2b' : '1px solid #eee',
      background: isDark ? '#2a0f1c' : '#fff',
      color: isDark ? '#f5d6e6' : '#333',
    },

    btn: {
      padding: '7px 12px',
      border: 'none',
      borderRadius: '8px',
      cursor: 'pointer',
      marginRight: '6px',
      fontWeight: 'bold',
      fontSize: '12px',
    },

    danger: { background: '#ff6b81', color: '#fff' },
    restore: { background: '#2ecc71', color: '#fff' },
    view: { background: '#6c63ff', color: '#fff' },
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>

        {/* TABS */}
        <div style={styles.tabs}>
          <button style={styles.tabBtn} onClick={() => setTab('users')}>
            Users ({users.length})
          </button>
          <button style={styles.tabBtn} onClick={() => setTab('posts')}>
            Posts ({posts.length})
          </button>
          <button style={styles.tabBtn} onClick={() => setTab('comments')}>
            Comments ({comments.length})
          </button>
        </div>

        {/* USERS */}
        {tab === 'users' && (
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>Name</th>
                <th style={styles.th}>Email</th>
                <th style={styles.th}>Status</th>
                <th style={styles.th}>Action</th>
              </tr>
            </thead>
            <tbody>
              {users.map(u => (
                <tr key={u._id}>
                  <td style={styles.td}>{u.name}</td>
                  <td style={styles.td}>{u.email}</td>
                  <td style={styles.td}>{u.status}</td>
                  <td style={styles.td}>
                    <button
                      style={{ ...styles.btn, ...styles.danger }}
                      onClick={() => toggleStatus(u._id)}
                    >
                      Toggle
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

        {/* POSTS */}
        {tab === 'posts' && (
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>Title</th>
                <th style={styles.th}>Status</th>
                <th style={styles.th}>Action</th>
              </tr>
            </thead>
            <tbody>
              {posts.map(p => (
                <tr key={p._id}>
                  <td style={styles.td}>{p.title}</td>
                  <td style={styles.td}>{p.status}</td>
                  <td style={styles.td}>

                    <button
                      style={{ ...styles.btn, ...styles.view }}
                      onClick={() => viewPost(p._id)}
                    >
                      View
                    </button>

                    {p.status === 'published' ? (
                      <button
                        style={{ ...styles.btn, ...styles.danger }}
                        onClick={() => removePost(p._id)}
                      >
                        Remove
                      </button>
                    ) : (
                      <button
                        style={{ ...styles.btn, ...styles.restore }}
                        onClick={() => restorePost(p._id)}
                      >
                        Undo
                      </button>
                    )}

                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

        {/* COMMENTS */}
        {tab === 'comments' && (
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>Author</th>
                <th style={styles.th}>Post</th>
                <th style={styles.th}>Comment</th>
                <th style={styles.th}>Action</th>
              </tr>
            </thead>
            <tbody>
              {comments.map(c => (
                <tr key={c._id}>
                  <td style={styles.td}>{c.author?.name}</td>
                  <td style={styles.td}>{c.post?.title}</td>
                  <td style={styles.td}>{c.body}</td>
                  <td style={styles.td}>

                    <button
                      style={{ ...styles.btn, ...styles.view }}
                      onClick={() => viewPost(c.post?._id)}
                    >
                      View Post
                    </button>

                    <button
                      style={{ ...styles.btn, ...styles.danger }}
                      onClick={() => removeComment(c._id)}
                    >
                      Delete
                    </button>

                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

      </div>
    </div>
  );
};

export default AdminPage;
